    cuenta_destino_id uuid,
    CONSTRAINT chk_solicitudes_estado CHECK (((estado)::text = ANY ((ARRAY['pendiente'::character varying, 'en_evaluacion'::character varying, 'observado'::character varying, 'aprobado'::character varying, 'rechazado'::character varying, 'desembolsado'::character varying, 'cancelado'::character varying])::text[]))),
    CONSTRAINT chk_solicitudes_monto CHECK ((monto > (0)::numeric)),
    CONSTRAINT chk_solicitudes_plazo CHECK (((plazo_meses >= 1) AND (plazo_meses <= 84)))
);


