--
-- Name: vw_bbva_cartera; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_bbva_cartera AS
 SELECT f.periodomes,
    a.codagencia,
    a.desagencia,
    p.desproducto AS producto,
    f.montosaldocapital AS cartera_total,
    f.car_vig_capital AS cartera_vigente,
    f.car_ven_capital AS cartera_vencida,
    f.diasatrasocredito AS dias_atraso,
        CASE
            WHEN (f.montosaldocapital > (0)::numeric) THEN round(((f.car_ven_capital / f.montosaldocapital) * (100)::numeric), 2)
            ELSE (0)::numeric
        END AS ratio_mora_porcentaje,
        CASE
            WHEN (f.diasatrasocredito = 0) THEN '01. Al día (0)'::text
            WHEN ((f.diasatrasocredito >= 1) AND (f.diasatrasocredito <= 6)) THEN '02. Preventiva (1-6)'::text
            WHEN ((f.diasatrasocredito >= 7) AND (f.diasatrasocredito <= 30)) THEN '03. Temprana (7-30)'::text
            WHEN ((f.diasatrasocredito >= 31) AND (f.diasatrasocredito <= 120)) THEN '04. Tardía (31-120)'::text
            WHEN ((f.diasatrasocredito >= 121) AND (f.diasatrasocredito <= 180)) THEN '05. Judicial (121-180)'::text
            ELSE '06. Castigo (>180)'::text
        END AS banda_mora
   FROM ((public.fagcuentacredito f
     JOIN public.dagencia a ON ((f.pkagencia = a.pkagencia)))
     JOIN public.dproducto p ON ((f.pkproducto = p.pkproducto)));


--
-- Name: vw_bbva_clientes; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_bbva_clientes AS
 SELECT au.id AS usuario_uuid,
    dc.pkcliente AS cliente_id,
    dc.codcliente AS codigo_cliente,
    au.dni,
    au.nombres,
    au.apellidos,
    au.correo,
    au.estado,
    au.fecha_registro
   FROM (public.app_usuarios au
     JOIN public.dcliente dc ON ((au.pkcliente = dc.pkcliente)));


--
-- Name: vw_bbva_cuentas; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_bbva_cuentas AS
 SELECT c.id AS cuenta_uuid,
    (((vc.nombres)::text || ' '::text) || (vc.apellidos)::text) AS cliente_nombre,
    c.tipo_cuenta,
    c.numero_cuenta,
    c.moneda,
    c.saldo,
    c.estado,
    c.created_at AS fecha_apertura
   FROM (public.cuentas c
     JOIN public.vw_bbva_clientes vc ON ((c.user_id = vc.usuario_uuid)));


--
-- Name: vw_bbva_homebanking_cuentas; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_bbva_homebanking_cuentas AS
 SELECT c.id,
    c.user_id,
    u.dni,
    u.nombres,
    u.apellidos,
    c.tipo_cuenta,
        CASE c.tipo_cuenta
            WHEN 'digital'::text THEN 'Cuenta Digital'::character varying
            WHEN 'independencia'::text THEN 'Cuenta Independencia'::character varying
            WHEN 'ganadora'::text THEN 'Cuenta Ganadora'::character varying
            WHEN 'sueldo'::text THEN 'Cuenta Sueldo'::character varying
            ELSE c.tipo_cuenta
        END AS nombre_producto,
    c.numero_cuenta,
    c.cci,
    c.saldo,
    c.moneda,
    c.estado,
    c.created_at
   FROM (public.cuentas c
     JOIN public.app_usuarios u ON ((u.id = c.user_id)));


--
-- Name: vw_bbva_metas_asesor; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_bbva_metas_asesor AS
 SELECT m.periodomes,
    ase.nomasesor AS asesor,
    m.saldocolocaciones_meta AS meta_colocaciones,
    m.saldocolocaciones_real AS real_colocaciones,
    round(((m.saldocolocaciones_real / m.saldocolocaciones_meta) * (100)::numeric), 2) AS cumplimiento_porcentaje,
    m.carteraatrasada_real AS mora_real,
    m.ratiomora_real AS ratio_mora_asesor
   FROM (public.fmetasasesor m
     JOIN public.dasesor ase ON ((m.pkasesor = ase.pkasesor)));


--
-- Name: vw_bbva_solicitudes; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_bbva_solicitudes AS
 SELECT s.id AS solicitud_uuid,
    (((vc.nombres)::text || ' '::text) || (vc.apellidos)::text) AS solicitante,
    s.monto,
    s.plazo_meses,
    s.tasa_anual,
    s.cuota_mensual,
    s.ingresos_mensuales,
    s.rds AS ratio_deuda_ingreso,
    s.semaforo_rds,
    s.nivel_aprobacion,
    s.estado,
    s.created_at AS fecha_solicitud
   FROM (public.solicitudes_prestamo s
     JOIN public.vw_bbva_clientes vc ON ((s.user_id = vc.usuario_uuid)));


--
-- Name: vw_bbva_solicitudes_credito_homebanking; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_bbva_solicitudes_credito_homebanking AS
 SELECT s.id,
    s.user_id,
    s.pkcliente,
    s.pksolicitud_core,
    s.monto,
    s.plazo_meses,
    s.tasa_anual,
    s.cuota_mensual,
    s.proposito,
    s.ingresos_mensuales,
    s.cuotas_actuales,
    s.rds,
    s.semaforo_rds,
    s.score,
    s.nivel_aprobacion,
    s.estado,
    s.created_at,
    s.updated_at,
    u.dni,
    u.nombres,
    u.apellidos,
    public.bbva_nivel_aprobacion(s.monto) AS nivel_aprobacion_calculado
   FROM (public.solicitudes_prestamo s
     JOIN public.app_usuarios u ON ((u.id = s.user_id)));


